+      logs.map((entry) => ({
+        id: entry.id,
+        level: entry.level,
+        message: entry.message,
+        data: entry.data,
+        timestamp: entry.timestamp.toISOString(),
+        durationMs: entry.durationMs,
+      })),
+    );
+  } catch (error) {
+    log.error({ error, jobId: id }, "Failed to get job logs");
+    return sendInternalError(c);
+  }
+});
+
+export default jobs;

