+    const result = await db
+      .delete(jobs)
+      .where(
+        sql`(status = 'completed' AND completed_at < ${completedCutoff}) OR (status = 'failed' AND completed_at < ${failedCutoff})`,
+      );
+
+    const deleted = result.changes;
+    if (deleted > 0) {
+      baseLogger.info({ deleted }, "Cleaned up old jobs");
+    }
+
+    return deleted;
+  }
+}
